def countOfAtoms(self, formula: str) -> str:
        stack = [{}]
        i = 0
        while i < len(formula):
            if formula[i] == '(':
                stack.append({})
                i += 1
            elif formula[i] == ')':
                top = stack.pop()
                i += 1
                start = i
                while i < len(formula) and formula[i].isdigit():
                    i += 1
                count = int(formula[start:i] or 1)
                for k in top:
                    top[k] *= count
                    stack[-1][k] = stack[-1].get(k, 0) + top[k]
            else:
                start = i
                i += 1
                while i < len(formula) and formula[i].islower():
                    i += 1
                name = formula[start:i]
                start = i
                while i < len(formula) and formula[i].isdigit():
                    i += 1
                count = int(formula[start:i] or 1)
                stack[-1][name] = stack[-1].get(name, 0) + count
        counts = []
        for k in sorted(stack[-1]):
            count = stack[-1][k]
            counts.append(k + (str(count) if count > 1 else ''))
        return ''.join(counts)

